const body = $json.body || $json;
const token = String(body.googleAccessToken || '').trim();
const messageId = String(body.messageId || '').trim();
const attachmentId = String(body.attachmentId || '').trim();
const mimeType = String(body.mimeType || '').trim();
const filename = String(body.filename || '').trim();

if (!token) throw new Error('googleAccessToken is required');
if (!messageId) throw new Error('messageId is required');
if (!attachmentId) throw new Error('attachmentId is required');
if (!mimeType) throw new Error('mimeType is required');
if (!filename) throw new Error('filename is required');

return {
  json: {
    token,
    messageId,
    attachmentId,
    mimeType,
    filename,
    _idx: 0,
  },
};

function fromBase64Url(input) {
  const normalized = String(input || '').replace(/-/g, '+').replace(/_/g, '/');
  const padLen = (4 - (normalized.length % 4)) % 4;
  return normalized + '='.repeat(padLen);
}

const row = $('Parse Extract Body').item.json;
const payload = $json || {};
const dataBase64Url = payload.data || '';

if (!dataBase64Url) {
  return {
    json: {
      ...row,
      _fileClass: 'error',
      _mimeType: row.mimeType || '',
      _geminiMimeType: row.mimeType || '',
      _fileName: row.filename || '',
      _downloadFailed: true,
      _status: 'Error: attachment fetch failed',
    },
  };
}

const base64 = fromBase64Url(dataBase64Url);
const binaryBuffer = Buffer.from(base64, 'base64');
const binary = await this.helpers.prepareBinaryData(
  binaryBuffer,
  row.filename || 'invoice',
  row.mimeType || 'application/octet-stream'
);

let fileClass = 'error';
let geminiMimeType = row.mimeType || 'application/octet-stream';
let status = '';

if (row.mimeType === 'application/pdf') {
  fileClass = 'document';
  geminiMimeType = 'application/pdf';
} else if (String(row.mimeType || '').startsWith('image/')) {
  fileClass = 'image';
  geminiMimeType = row.mimeType;
} else {
  status = 'unsupported';
}

return {
  json: {
    ...row,
    _fileClass: fileClass,
    _mimeType: row.mimeType || '',
    _geminiMimeType: geminiMimeType,
    _fileName: row.filename || '',
    _downloadFailed: false,
    _status: status,
  },
  binary: { invoiceFile: binary },
};

const OPENROUTER_MODEL = 'google/gemini-2.5-flash';

const OPENROUTER_REQUEST_OPTIONS = {
  model: OPENROUTER_MODEL,
  max_tokens: 1024,
  response_format: { type: 'json_object' },
  // Disable reasoning for direct JSON extraction.
  reasoning: { effort: 'none' },
};

const EXTRACTION_PROMPT = `You are reading an invoice document. Extract ONLY these four fields and return valid JSON with no prose, no markdown, no code fences:

{"payee":"string","account_number":"string","ifsc":"string","amount":"string","confidence":0.0}

Rules:
- payee: the account payee or beneficiary name exactly as printed on THIS invoice
- account_number: digits only, no spaces or dashes — copy exactly from the document
- ifsc: exactly 11 characters, uppercase, copied from the document (format: 4 letters + 0 + 6 alphanumeric)
- amount: invoice total or grand total as printed (digits and decimal point only, no currency symbols or commas)
- confidence: 0.0 to 1.0 — use 0.0 if you cannot read the document clearly
- If a field is missing or unreadable, use "" and set confidence below 0.5
- NEVER invent, guess, or reuse placeholder values — only copy text visible on the invoice`;

const row = $('Restore Row After Download').item.json;

function checksumHex(buffer) {
  let hash = 2166136261;
  for (const byte of buffer) {
    hash ^= byte;
    hash = Math.imul(hash, 16777619);
  }
  return (hash >>> 0).toString(16);
}

function debugLog(hypothesisId, location, message, data) {
  // #region agent log
  if (typeof fetch === 'function') {
    fetch('http://127.0.0.1:7278/ingest/2c22404a-379e-4acd-837f-babf35680249',{method:'POST',headers:{'Content-Type':'application/json','X-Debug-Session-Id':'86ecbf'},body:JSON.stringify({sessionId:'86ecbf',runId:'exec107-investigation',hypothesisId,location,message,data,timestamp:Date.now()})}).catch(()=>{});
  }
  // #endregion
}

if (row._downloadFailed) {
  return { json: { error: row._status || 'Invoice file unavailable', _skipOpenRouter: true } };
}

if (row._officeDocText) {
  const _openRouterBody = {
    ...OPENROUTER_REQUEST_OPTIONS,
    messages: [
      {
        role: 'user',
        content:
          EXTRACTION_PROMPT +
          '\n\n--- Invoice document text ---\n' +
          row._officeDocText,
      },
    ],
  };
  return {
    json: {
      _openRouterBody,
      _openRouterModel: OPENROUTER_MODEL,
      _prepareMime: 'text/plain',
      _prepareIdx: row._idx,
      _prepareMode: 'text',
    },
  };
}

const bin = $input.item.binary?.invoiceFile || $binary?.invoiceFile || null;
if (!bin) {
  return { json: { error: 'No invoice file binary found for OpenRouter analysis' } };
}

const itemIndex = typeof $itemIndex === 'number' ? $itemIndex : 0;
const buffer = await this.helpers.getBinaryDataBuffer(itemIndex, 'invoiceFile');
const base64 = Buffer.from(buffer).toString('base64');
const fileChecksum = checksumHex(buffer);

let mime = row._geminiMimeType || row._mimeType || bin.mimeType || 'application/octet-stream';

if (mime === 'application/octet-stream' && row._fileClass === 'image') {
  mime = 'image/jpeg';
}

const dataUrl = `data:${mime};base64,${base64}`;

debugLog('H1', 'prepareOpenRouterPayload.js:post-binary', 'Prepared binary for OpenRouter', {
  idx: row._idx,
  fileId: row._fileId || '',
  fileName: row._fileName || bin.fileName || '',
  convertedFromOffice: !!row._convertedFromOffice,
  mime,
  byteLength: buffer.length,
  fileChecksum,
});

function buildVisionContent(prompt) {
  if (mime === 'application/pdf') {
    return [
      {
        type: 'file',
        file: {
          filename: row._fileName || bin.fileName || 'invoice.pdf',
          file_data: dataUrl,
        },
      },
      { type: 'text', text: prompt },
    ];
  }

  return [
    {
      type: 'image_url',
      image_url: { url: dataUrl },
    },
    { type: 'text', text: prompt },
  ];
}

const _openRouterBody = {
  ...OPENROUTER_REQUEST_OPTIONS,
  messages: [
    {
      role: 'user',
      content: buildVisionContent(EXTRACTION_PROMPT),
    },
  ],
};

debugLog('H2', 'prepareOpenRouterPayload.js:payload-shape', 'Built OpenRouter request payload', {
  idx: row._idx,
  mode: 'vision',
  mime,
  contentType: mime === 'application/pdf' ? 'file+text' : 'image_url+text',
  fileChecksum,
});

return {
  json: {
    _openRouterBody,
    _openRouterModel: OPENROUTER_MODEL,
    _prepareMime: mime,
    _prepareIdx: row._idx,
    _prepareMode: 'vision',
    _prepareFileId: row._fileId || '',
    _prepareByteLength: buffer.length,
    _prepareFileChecksum: fileChecksum,
  },
};

const IFSC_REGEX = /^[A-Z]{4}0[A-Z0-9]{6}$/;

function extractRawModelText(data) {
  if (!data) return '';
  if (typeof data.text === 'string') return data.text;
  if (typeof data.output === 'string') return data.output;
  if (typeof data.content === 'string') return data.content;
  const openAiContent = data.choices?.[0]?.message?.content;
  if (typeof openAiContent === 'string') return openAiContent;
  if (Array.isArray(openAiContent)) {
    return openAiContent
      .filter((part) => part?.type === 'text' && typeof part.text === 'string')
      .map((part) => part.text)
      .join('');
  }
  const openAiText = data.choices?.[0]?.text;
  if (typeof openAiText === 'string') return openAiText;
  const messageContent = data.message?.content;
  if (typeof messageContent === 'string') return messageContent;
  const partText = data.content?.parts?.[0]?.text;
  if (typeof partText === 'string') return partText;
  return '';
}

function normalizeAmount(val) {
  const s = String(val ?? '').trim();
  if (!s) return '';
  return s.replace(/[^\d.]/g, '');
}

function normalizeConfidence(raw, payee, acct, ifsc, amount) {
  if (typeof raw === 'number' && raw > 0) return Math.min(1, raw);
  const filled = [payee, acct, ifsc, amount].filter(Boolean).length;
  if (filled === 0) return 0;
  return Math.min(0.95, 0.45 + filled * 0.12);
}

function normalizeExtractionFields(p) {
  return {
    payee: String(p.payee ?? p.account_name ?? p.beneficiary ?? p.account_payee ?? '').trim(),
    account_number: String(
      p.account_number ??
        p.accountNumber ??
        p.bank_number ??
        p.bank_account_number ??
        p.bank_account ??
        ''
    ).replace(/\D/g, ''),
    ifsc: String(p.ifsc ?? p.IFSC ?? p.ifsc_code ?? '').toUpperCase().trim(),
    amount: normalizeAmount(
      p.amount ?? p.total ?? p.total_amount ?? p.invoice_amount ?? p.invoice_total
    ),
    confidence: typeof p.confidence === 'number' ? p.confidence : 0,
  };
}

function hasExtractionFields(data) {
  if (!data || typeof data !== 'object') return false;
  return (
    data.payee !== undefined ||
    data.account_name !== undefined ||
    data.beneficiary !== undefined ||
    data.account_number !== undefined ||
    data.accountNumber !== undefined ||
    data.bank_account_number !== undefined ||
    data.ifsc !== undefined ||
    data.IFSC !== undefined ||
    data.amount !== undefined ||
    data.total !== undefined
  );
}

function parseExtractionPayload(data) {
  if (hasExtractionFields(data)) {
    return normalizeExtractionFields(data);
  }
  const raw = extractRawModelText(data);
  if (!raw) return null;
  const cleaned = raw.replace(/```json?\n?/gi, '').replace(/```/g, '').trim();
  try {
    return normalizeExtractionFields(JSON.parse(cleaned));
  } catch (_) {
    const match = cleaned.match(/\{[\s\S]*\}/);
    if (!match) return null;
    return normalizeExtractionFields(JSON.parse(match[0]));
  }
}

function detectHallucination(payee, acct, ifsc) {
  if (acct.length >= 10 && /^(\d)\1+$/.test(acct)) return 'repeated-digit account number';
  if (ifsc && !IFSC_REGEX.test(ifsc)) return 'invalid IFSC format';
  return '';
}

function finalizeExtraction(p) {
  const payee = p.payee;
  const acct = p.account_number;
  const ifsc = p.ifsc;
  const amount = p.amount;
  const confidence = normalizeConfidence(p.confidence, payee, acct, ifsc, amount);
  return { payee, acct, ifsc, amount, confidence };
}

